class LFUCache {
private:
    int capacity, minFreq;
    unordered_map<int, pair<int, int>> keyToValAndFreq;
    unordered_map<int, list<int>> freqToKeyList;
    unordered_map<int, list<int>::iterator> keyToIterator;

public:
    LFUCache(int capacity) : capacity(capacity), minFreq(0) {}

    int get(int key) {
        if (!keyToValAndFreq.count(key)) return -1;
        int freq = keyToValAndFreq[key].second;
        freqToKeyList[freq].erase(keyToIterator[key]);
        if (freqToKeyList[freq].empty() && minFreq == freq) minFreq++;
        keyToValAndFreq[key].second++;
        freqToKeyList[freq + 1].push_front(key);
        keyToIterator[key] = freqToKeyList[freq + 1].begin();
        return keyToValAndFreq[key].first;
    }

    void put(int key, int value) {
        if (capacity == 0) return;
        if (keyToValAndFreq.count(key)) {
            keyToValAndFreq[key].first = value;
            get(key); // Increase frequency
            return;
        }
        if (keyToValAndFreq.size() == capacity) {
            int keyToEvict = freqToKeyList[minFreq].back();
            freqToKeyList[minFreq].pop_back();
            keyToValAndFreq.erase(keyToEvict);
            keyToIterator.erase(keyToEvict);
        }
        keyToValAndFreq[key] = {value, 1};
        freqToKeyList[1].push_front(key);
        keyToIterator[key] = freqToKeyList[1].begin();
        minFreq = 1;
    }
};

